案例代码:
entity top_ent is 
port( 
	 clk : in std_logic; 
	 sys_rst : in std_logic; 
	 D_in : in std_logic_vector(2 downto 0); 
	 D_out : out std_logic_vector(2 downto 0) );
end top_ent; 
architecture behave_arc of top_ent is 
signal rst_n, rst:std_logic;
signal S_Dout_temp_r:std_logic_vector(2 downto 0);
begin 
rst_n <= sys_rst;
rst <= not sys_rst;
process (clk, rst_n,rst) 
  begin
    if rst_n= '0' then 
	  S_Dout_temp_r <= "000"; 
	elsif  rst= '1' then      --寄存器S_Dout_temp_r的复位和置位来自同一信号sys_rst，可能会导致竞争与冒险
	  S_Dout_temp_r <= "111"; 
	elsif clk'event and clk= '1'then
	  S_Dout_temp_r <= D_in; 
	end if; 
  end process;
D_out <= S_Dout_temp_r;
end behave_arc;

