entity example_ent is 
port( 
	 clk : in std_logic; 
	 rst_n : in std_logic; 
	 sel1 : in std_logic; 
	 sel2 : in std_logic; 
	 din : in std_logic; 
	 dout : out std_logic ) ;
end example_ent; 
architecture behave_arc of example_ent is signal clkl : std_logic; 
signal clk2 : std_logic; 
signal clk_sel : std_logic; 
begin 
  clkl <= sell and clk; 
  clk2 <= sel2 or clk; 
  clk_sel <= clkl and clk2;   --此处的时钟信号在时钟网络上发生了再汇聚
process (rst_n, clk_sel)
  begin
    if(rst_n ='0')then 
	  dout <='0'; 
	elsif clk_sel'event and clk_sel ='1' then
	  dout <= din;
	end if; 
end process; 
end behave_arc;

