entity top_ent is 
port( 
	 clk : in std_logic; 
	 rst_n : in std_logic; 
	 D_in : in std_logic; 
	 D_out : out std_logic );
end top_ent; 
architecture behave_arc of top_ent is 
signal S_Doutl_r, S_Dout_temp_r : std_logic; 
begin 
process (clk, rst_n) 
  begin
    if rst_n= '0' then 
	  S_Dout_temp_r <= 0; 
	elsif clk'event and clk= '1'then             --此处使用时钟信号上升沿
	  S_Dout_temp_r <= D_in; 
	end if; 
  end process; 
process (clk, rst_n)
  begin
	if rst_n= '0' then 
	  D_out <= 0; 
	elsif clk'event and clk= '0'then             --此处使用时钟信号下降沿
	  D_out <= S_Dout_temp_r; 
	end if;
  end process; 
end behave_arc;

