案例代码:
entity dff is
port (
D, CLK, RESET : in std_logic;
Q : out std_logic
);
end entity;
architecture dff_rtl of dff is
begin
process ( CLK, RESET ) is
begin
if (RESET) then
Q <= '1';
elsif (RISING_EDGE(CLK))
Q <= D;
end if;
end process;
end architecture;
entity mux is
port (
in1, in2, sel : in std_logic;
out1 : out std_logic
);
end entity;
architecture mux_rtl of mux is
begin
out1 <= in1 when sel = '1' else in2;
end architecture;
entity top is
port (
in1, in2, in3, clk1, clk2, reset, sel : in std_logic;      --clk1被同时用作时钟和复位
out1, out2 : out std_logic
);
end entity;
architecture top_rtl of top is
signal mux_to_ff1, mux_to_ff2 : std_logic;
begin
mux_to_ff2 <= clk1 when sel = '1' else
in3;
MUX_INSTANCE : entity mux port map ( in1 =>
clk1, in2 => in2 , sel => sel, out1 => mux_to_ff1
);
DFF_INSTANCE1 : entity dff port map ( D => in1, CLK => mux_to_ff1, RESET => reset , Q => out1 );   --clk1连接到top.DFF_INSTANCE1的时钟端
DFF_INSTANCE2 : entity dff port map ( D => in1, CLK => clk2, RESET => mux_to_ff2, Q => out2 );     --clk1连接到top.DFF_INSTANCE2的复位端
end architecture;

案例代码:
--第一个进程，同步时序进程，描述次态寄存器迁移到现态寄存器
process (rst_n, clk) 
begin
  if rst_n ='0'then 
	current_state_r <= IDLE; 
  elsif rising_edge(clk) then
	current_state_r <= next_state_r; 
  end if; 
end process; 
--第二个进程，组合逻辑进程，描述状态转移条件判断
process (current_state_r, AD_start,...) 
begin
  next_state_r <= IDLE; 
  case current_state_r is 
    when IDLE =>
	  if AD_start= '1' then
	    next_state_r <= STATE_l;
	  else
	    next_state_r <= IDLE;
	  end if;
	when STATE_l =>
	  next_state_r <= STATE_2;
	  .......
	when others =>
	  next_state_r <= IDLE;
  end case;
end process;
--第三个进程，同步时序进程，描述次态寄存器输出
process (rst_n, clk) 
begin 
  if rst_n = '0' then
    AD_CS <= 'l'; 
    AD_RD <= 'l'; 
	AD DONE <= "00"; 
	......
  elsif rising_edge(clk) then
    case next_state_r is 
	when IDLE =>
	  AD_CS <='l'; 
	  AD_RD <= '1'; 
	  AD_DONE <= '0';
	  ......
	end case;
  end if;
end process;

