entity example_ent is 
port( 
	 a_in : in std_logic; -- a_in为外部的异步信号 
	 clk : in std_logic; 
	 d_out : out std_logic_vector (1 downto 0)); 
end example_ent; 
architecture behave_arc of example_ent is 
signal S_cnt : std_logic_vector(l downto 0); 
begin 
process (clk) 
  begin 
    if clk'event and clk ='1'then
	  if(a_in ='1') then     --a_in为外部的异步信号，此处未经同步化直接使用
		S_cnt <= S_cnt + 1; 
	  end if; 
	end if;
  end process;
d_out <= S_cnt; 
end behave_arc;

