entity basic_ent is
port (A, B: in std_logic_vector (3 downto 0);
  Q: out std_logic_vector(2 downto 0));
end basic_ent;
architecture basic of basic_ent is
begin
  basic_block: block is begin
process ( A ) is
variable T: std_logic_vector ( 5 downto 1 );
variable W: std_logic_vector ( 15 downto 1 );
variable R: boolean;
variable E: std_logic_vector ( 10 downto 1 );
begin
if ( T = E ) then          --关系操作符“=”右边的10位与左边5位宽度不一致
  Q <= "11";            --赋值语句左边3位与右边2位宽度不一致
else
  Q <= Q;           
end if;
end process;
end block;
end basic;

