signal count : integer 0 to 3;
SUM: for i in 1 to count loop    --用于控制循环终止条件的参数应为常量
sum = sum+ i; 
end loop SUM;

案例代码:
entity example_ent is 
port( 
	 a_in : in std_logic;
	 b_in : in std_logic; 
	 d_in : in std_logic; 
	 d_out : out std_logic);
end example_ent; 
architecture behave_arc of example_ent is 
signal clk : in std_logic; 
begin 
  clk <= a_in and b_in;  --组合逻辑产生时钟
process (clk) 
  begin
    if clk'event and clk ='1' then  --使用组合逻辑产生的时钟
	  d_out <= d_in; 
	end if;
  end if;
  end process; 
end behave_arc;

